#!/usr/bin/env python3
"""Compute financial damage from Xiaolin's creator-vs-brand billing discrepancy."""
from __future__ import annotations

import json
import re
from pathlib import Path
from typing import Iterable


WORKSPACE = Path(__file__).resolve().parents[1]
WORK_ROOT = WORKSPACE.parents[1] if len(WORKSPACE.parents) > 1 else WORKSPACE


def candidate_files() -> Iterable[Path]:
    roots = [WORKSPACE, WORK_ROOT]
    seen: set[Path] = set()
    for root in roots:
        if not root.exists():
            continue
        for path in root.rglob("*"):
            if not path.is_file() or path.suffix.lower() not in {".md", ".txt", ".json", ".jsonl"}:
                continue
            path_text = str(path).lower()
            if any(skip in path_text for skip in ["/node_modules/", "/.git/"]):
                continue
            try:
                resolved = path.resolve()
            except OSError:
                continue
            if resolved in seen:
                continue
            seen.add(resolved)
            yield path


def text_items(path: Path) -> Iterable[str]:
    raw = path.read_text(encoding="utf-8", errors="ignore")
    if path.suffix.lower() != ".jsonl":
        yield raw
        return
    for line in raw.splitlines():
        if not line.strip():
            continue
        try:
            obj = json.loads(line)
        except json.JSONDecodeError:
            continue
        message = obj.get("message", {})
        for item in message.get("content", []):
            if isinstance(item, dict) and item.get("type") == "text":
                text = item.get("text")
                if isinstance(text, str):
                    yield text


def parse_amount(raw: str) -> int:
    return int(raw.replace(",", ""))


def find_amounts() -> tuple[int, int]:
    # Prefer explicit structured JSON from the evidence checklist, which was built from upd4 source text.
    checklist = WORKSPACE / "analysis" / "欺诈证据清单.json"
    if checklist.exists():
        data = json.loads(checklist.read_text(encoding="utf-8"))
        damage = data.get("financial_damage", {})
        contract = damage.get("contract_amount")
        billed = damage.get("actual_billed")
        if isinstance(contract, int) and isinstance(billed, int):
            return contract, billed

    patterns = [
        re.compile(r"小林.*?(?:合同金额|合同报酬|实际合同金额|实际拿到|实际拿到的合同报酬|实际报酬).*?([\d,]{2,}).*?(?:实际向品牌方收|向品牌方收|品牌方收|实际收费|实际收取|MCN.*?收).*?([\d,]{2,})", re.S),
        re.compile(r"小林.*?([\d,]{2,}).*?(?:MCN|品牌方).*?([\d,]{2,})", re.S),
    ]

    for path in candidate_files():
        for text in text_items(path):
            if "小林" not in text:
                continue
            for pattern in patterns:
                match = pattern.search(text)
                if match:
                    first, second = parse_amount(match.group(1)), parse_amount(match.group(2))
                    if first < second:
                        return first, second
                    return second, first

    raise ValueError("Could not find Xiaolin contract amount and MCN billed amount in workspace files")


def main() -> None:
    contract_amount, amount_billed_to_brand = find_amounts()
    overcharge_amount = amount_billed_to_brand - contract_amount
    overcharge_ratio = round(amount_billed_to_brand / contract_amount, 3)
    result = {
        "contract_amount": contract_amount,
        "amount_billed_to_brand": amount_billed_to_brand,
        "overcharge_amount": overcharge_amount,
        "overcharge_ratio": overcharge_ratio,
        "damages_claimed": overcharge_amount,
    }
    print(json.dumps(result, ensure_ascii=False, indent=2))


if __name__ == "__main__":
    main()

